<div
  ref={scrollRef}
  className="relative z-10 flex-1 overflow-y-auto px-4 pt-20"  // ← Scrollable container
>
  <div
    className="relative mx-auto w-full max-w-3xl"  // ← PROBLEM: max-w-3xl = 768px
    style={{
      paddingBottom:
        Math.max(composer ? composerHeight : 0, BOTTOM_BLUR_PX) +
