### 4. WHERE TOOL CARDS ARE DEFINED

#### **ToolCard.tsx** — `/Users/aryan/Projects/GAIA/gaia-onboarding-revamp/apps/web/src/config/openui/primitives/ToolCard.tsx`

(Lines 1-50)
```tsx
export type ToolCardSize = "compact" | "standard" | "wide" | "full";

const SIZE_MAX_W: Record<ToolCardSize, string> = {
  compact: "max-w-md",      // 448px
  standard: "max-w-2xl",    // 672px
  wide: "max-w-4xl",        // 896px ← TextDocumentView uses this
  full: "",
};

export function ToolCard({
  size = "standard",
  title,
  subtitle,
  footer,
  className,
  children,
}: ToolCardProps) {
  return (
    <div
      className={cn(
        "rounded-2xl bg-zinc-800 p-4 w-full",
        SIZE_MAX_W[size],    // ← Applied here
        className,
      )}
    >
      {hasHeader && (
        <div className="mb-3">
          {title && (
            <p className="text-sm font-semibold text-zinc-100">{title}</p>
          )}
          {subtitle && (
            <p className="text-xs text-zinc-400 mt-0.5">{subtitle}</p>
          )}
        </div>
      )}
      <div className="flex flex-col gap-3">{children}</div>
      {footer && <div className="mt-3">{footer}</div>}
    </div>
  );
}
```

**Problem:** When `size="wide"`, the card is `max-w-4xl` (896px), which **exceeds** the onboarding's `max-w-3xl` (768px) parent constraint by 128px.

