### 5. HOW MESSAGES WITH TOOL CARDS FLOW THROUGH CHAT

#### **TextBubble.tsx** — `/Users/aryan/Projects/GAIA/gaia-onboarding-revamp/apps/web/src/features/chat/components/bubbles/bot/TextBubble.tsx`

(Lines 245-330) — Tool card rendering logic
```tsx
const TOOL_RENDERERS: Partial<RendererMap> = {
  document_data: (data, index) => (
    <DocumentSection
      key={`tool-doc-${index}`}
      document_data={data as DocumentData}
    />
  ),
  // ... other tool renderers
};

export default function TextBubble({
  text,
  disclaimer,
  tool_data,
  isConvoSystemGenerated,
  systemPurpose,
  loading,
}: ChatBubbleBotProps) {
  // ...
  return (
    <>
      {parsedContent.thinking && (
        <ThinkingBubble thinkingContent={parsedContent.thinking} />
      )}

      {processedTools.map((entry, index) => {
        const toolName = entry.tool_name as ToolName;
        // ... tool rendering
        return (
          <React.Fragment key={toolKey}>
            {renderTool(toolName, typedData, index)}
          </React.Fragment>
        );
      })}

      {shouldShowTextBubble(text, isConvoSystemGenerated, systemPurpose) &&
        (() => {
          // ... text rendering with markdown/openui
        })()}
    </>
  );
}
```

Tool cards are rendered at the bubble level, inheriting the parent's width constraint.

#### **ChatBubbleBot.tsx** — `/Users/aryan/Projects/GAIA/gaia-onboarding-revamp/apps/web/src/features/chat/components/bubbles/bot/ChatBubbleBot.tsx`

(Lines 100-170)
```tsx
<div
  id={message_id}
  onMouseOver={handleMouseOver}
  onMouseOut={handleMouseOut}
  className="relative flex flex-col"
  style={{ contentVisibility: "auto", containIntrinsicSize: "0 120px" }}
>
  <div className="flex items-end gap-1">
    {!hideAvatar && (
      <div className="relative bottom-0 min-w-10 shrink-0">
        {showBubbleChrome && (
          <m.div className={...}>
            <Image alt="GAIA Logo" src={...} width={30} height={30} />
          </m.div>
        )}
      </div>
    )}

    <div className="chatbubblebot_parent flex-1">  // ← flex-1, grows to parent width
      <div className="flex w-full flex-col gap-2">
        <MemoryIndicator {...} />
        <div className="chat_bubble_container">{renderedComponent}</div>
      </div>
    </div>
  </div>

  {showBubbleChrome && (
    <div className="ml-10.75 flex flex-col">
