1	/**
2	 * Full-screen layout wrapper for the onboarding page. Three regions: top
3	 * progress bar, scrollable content (caller-supplied children), and an
4	 * optional pinned composer at the bottom. Auto-scrolls the content region
5	 * to bottom whenever stage- or content-bearing state changes.
6	 */
7	
8	"use client";
9	
10	import type { ReactNode } from "react";
11	import { useEffect, useMemo, useRef, useState } from "react";
12	import BlurStack, { type BlurLayer } from "@/components/ui/blur-stack";
13	import { getProgress, PROGRESS_TOTAL_STEPS } from "../state/derive";
14	import type { OnboardingState, Stage } from "../state/types";
15	import { OnboardingProgress } from "./OnboardingProgress";
16	
17	// Heavy-blur-at-top config — mirror of the default heavy-at-bottom stack.
18	const TOP_BLUR_CONFIG: BlurLayer[] = [
19	  { blur: 0.5, maskStops: [62.5, 75, 87.5, 100], zIndex: 1 },
20	  { blur: 1, maskStops: [50, 62.5, 75, 87.5], zIndex: 2 },
21	  { blur: 2, maskStops: [37.5, 50, 62.5, 75], zIndex: 3 },
22	  { blur: 4, maskStops: [25, 37.5, 50, 62.5], zIndex: 4 },
23	  { blur: 8, maskStops: [12.5, 25, 37.5, 50], zIndex: 5 },
24	  { blur: 16, maskStops: [0, 12.5, 25, 37.5], zIndex: 6 },
25	  { blur: 32, maskStops: [0, 0, 12.5, 25], zIndex: 7 },
26	  { blur: 64, maskStops: [0, 0, 0, 12.5], zIndex: 8 },
27	];
28	
29	interface OnboardingShellProps {
30	  state: OnboardingState;
31	  stage: Stage;
32	  onRestart: () => void;
33	  children: ReactNode;
34	  composer?: ReactNode;
35	}
36	
37	/**
38	 * Single string fingerprint of "what's on screen". Used as a useEffect dep so
39	 * scroll-to-bottom fires once per content change instead of needing 7 deps.
40	 */
41	function getContentFingerprint(state: OnboardingState, stage: Stage): string {
42	  const b = state.server;
43	  // Concat every active progress slot — any change to any stage's status_text
44	  // should re-trigger the scroll-to-bottom effect.
45	  const progress = Object.values(state.progressByStage).join("");
46	  return [
47	    stage,
48	    state.questionIndex,
49	    progress,
50	    state.completedStages.size,
51	    state.ackedWritingStyle ? 1 : 0,
52	    state.ackedTodos ? 1 : 0,
53	    state.workflowsConfirmed ? 1 : 0,
54	    state.platformsConfirmed ? 1 : 0,
55	    state.connectedPlatform ?? "",
56	    b?.writing_style?.style_summary ?? "",
57	    b?.onboarding_todos?.length ?? 0,
58	    b?.suggested_workflows?.length ?? 0,
59	    b?.first_message_conversation_id ?? "",
60	    state.todoExecutionMessage ?? "",
61	    Object.keys(state.clarifyAnswers).length,
62	    state.clarifySubmitted ? 1 : 0,
63	  ].join("|");
64	}
65	
66	const COMPOSER_GUTTER_PX = 24;
67	const BOTTOM_BLUR_PX = 96;
68	
69	export function OnboardingShell({
70	  state,
71	  stage,
72	  onRestart,
73	  children,
74	  composer,
75	}: OnboardingShellProps) {
76	  const scrollRef = useRef<HTMLDivElement>(null);
77	  const composerRef = useRef<HTMLDivElement>(null);
78	  const [composerHeight, setComposerHeight] = useState(0);
79	  const progressStep = getProgress(state, stage);
80	  const fingerprint = useMemo(
81	    () => getContentFingerprint(state, stage),
82	    [state, stage],
83	  );
84	
85	  const hasComposer = !!composer;
86	  useEffect(() => {
87	    const el = composerRef.current;
88	    if (!el) {
89	      setComposerHeight(0);
90	      return;
91	    }
92	    const update = () => setComposerHeight(el.getBoundingClientRect().height);
93	    update();
94	    const obs = new ResizeObserver(update);
95	    obs.observe(el);
96	    return () => obs.disconnect();
97	  }, [hasComposer, stage]);
98	
99	  useEffect(() => {
100	    scrollRef.current?.scrollTo({
101	      top: scrollRef.current.scrollHeight,
102	      behavior: "smooth",
103	    });
104	  }, [fingerprint, composerHeight]);
105	
106	  return (
107	    <div className="fixed inset-0 z-50 flex flex-col bg-primary-bg backdrop-blur-2xl">
108	      <div
109	        aria-hidden
110	        className="pointer-events-none absolute inset-0 z-0 bg-center bg-cover opacity-40"
111	        style={{
112	          backgroundImage: "url('/images/wallpapers/bands_gradient_black.png')",
113	        }}
114	      />
115	      <OnboardingProgress
116	        currentStep={progressStep}
117	        totalSteps={PROGRESS_TOTAL_STEPS}
118	        onRestart={onRestart}
119	        isRestarting={state.isRestarting}
120	      />
121	
122	      <div
123	        ref={scrollRef}
124	        className="relative z-10 flex-1 overflow-y-auto px-4 pt-20"
125	      >
126	        <div
127	          className="relative mx-auto w-full max-w-3xl"
128	          style={{
129	            paddingBottom:
130	              Math.max(composer ? composerHeight : 0, BOTTOM_BLUR_PX) +
131	              COMPOSER_GUTTER_PX,
132	          }}
133	        >
134	          {children}
135	        </div>
136	      </div>
137	
138	      <BlurStack
139	        className="pointer-events-none fixed top-0 right-0 left-0 z-20 h-24"
