.chat_bubble::selection {
  background: #fff;
  color: #0bf;
}

.chat_bubble_container {
  align-items: flex-start;
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.chat_bubble_container.user {
  align-items: flex-end;
}

/* iMessage-style chat bubbles */
.imessage-bubble {
  word-wrap: break-word;
  line-height: 24px;
  position: relative;
  padding: 8px 20px;
  max-width: 60vw;
  border-radius: 20px;
}

/*
 * Tail rendered as a single pseudo-element with clip-path tracing the
 * exact iMessage tail silhouette. The clipped path matches the visible
 * region produced by the previous ::before/::after bg-color trick — same
 * shape, but a real cutout, so it composites correctly over any
 * background (image, gradient, transparent, etc.).
 *
 * Geometry: 20px × 18px box anchored to the bubble's bottom-left
 * (from-them) or bottom-right (from-me, mirrored).
 */
.imessage-bubble::before {
  content: "";
  position: absolute;
  bottom: 0;
  width: 20px;
  height: 18px;
}

.imessage-grouped-first,
.imessage-grouped-last,
.imessage-grouped-middle {
  border-radius: 20px;
}

.imessage-from-them {
  background: #27272a;
  align-self: flex-start;
}

.imessage-from-them::before {
  left: -7px;
  background-color: #27272a;
  clip-path: path(
    "M 20 0 L 20 2 A 16 16 0 0 1 4 18 L 0 18 L 0 17.54 A 10 10 0 0 0 7 8 L 7 0 Z"
  );
}

.imessage-from-me {
  color: black;
  background: #00bbff;
  align-self: flex-end;
}

.imessage-from-me::before {
  right: -7px;
  background-color: #00bbff;
  clip-path: path(
    "M 0 0 L 0 2 A 16 16 0 0 0 16 18 L 20 18 L 20 17.54 A 10 10 0 0 1 13 8 L 13 0 Z"
  );
}

/* Hide tails for grouped messages except the last one */
.imessage-grouped-first::before,
.imessage-grouped-middle::before {
  display: none;
}

.conversation_history {
  display: flex;
  flex-direction: column;
  height: fit-content;
  justify-content: flex-start;
  min-height: 70vh;
  padding: 2rem 0 2rem -0.5rem;
}

/* content-visibility: skip rendering off-screen items in long lists */
.cv-auto {
  content-visibility: auto;
}

.cv-chat-message {
  content-visibility: auto;
  contain-intrinsic-size: 0 120px;
}

.cv-notification-card {
  content-visibility: auto;
  contain-intrinsic-size: 0 100px;
}

.cv-todo-item {
  content-visibility: auto;

