1	/**
2	 * Top-level orchestrator page for the onboarding flow. Uses `useOnboarding`
3	 * to get the derived stage, then picks a `stageContent` and a `composer`
4	 * for that stage. Stage-driven swapping keeps each stage's logic isolated;
5	 * shared transcript + progress chrome live in `OnboardingShell` /
6	 * `MessagesRegion`. `skipAutoRedirect` keeps the chat stage rendered here
7	 * instead of redirecting into the standalone `/c/:id` route.
8	 */
9	
10	"use client";
11	
12	import { AnimatePresence } from "motion/react";
13	import * as m from "motion/react-m";
14	import { useEffect, useState } from "react";
15	import { CompletedStagesTimeline } from "@/features/onboarding/components/CompletedStagesTimeline";
16	import { MessagesRegion } from "@/features/onboarding/components/MessagesRegion";
17	import { OnboardingIntro } from "@/features/onboarding/components/OnboardingIntro";
18	import { OnboardingShell } from "@/features/onboarding/components/OnboardingShell";
19	import {
20	  Chat,
21	  ChatComposer,
22	  ClarifyComposer,
23	  FocusComposer,
24	  Platforms,
25	  PlatformsComposer,
26	  QuestionsComposer,
27	  RevealTodos,
28	  RevealTodosComposer,
29	  RevealWritingStyle,
30	  RevealWritingStyleComposer,
31	  useChatStage,
32	  Workflows,
33	  WorkflowsComposer,
34	} from "@/features/onboarding/components/stages";
35	import { EASE_OUT_QUART } from "@/features/onboarding/constants/motion";
36	import { useOnboarding } from "@/features/onboarding/hooks/useOnboarding";
37	import { useUserStore } from "@/stores/userStore";
38	
39	const INTRO_FADE_IN = {
40	  initial: { opacity: 0, filter: "blur(12px)" },
41	  animate: { opacity: 1, filter: "blur(0px)" },
42	  transition: { duration: 0.6, ease: EASE_OUT_QUART },
43	} as const;
44	
45	const INTRO_SEEN_PREFIX = "gaia.onboarding.introSeen";
46	
47	// Keyed per-user so a new account still gets the intro, while the same
48	// user reloading (or coming back from an external OAuth redirect that lands
49	// them in a fresh browsing context, e.g. Arc's Little Arc) skips it.
50	function introSeenKey(userId: string): string | null {
51	  return userId ? `${INTRO_SEEN_PREFIX}.${userId}` : null;
52	}
53	
54	function hasSeenIntro(userId: string): boolean {
55	  if (typeof window === "undefined") return false;
56	  const key = introSeenKey(userId);
57	  if (!key) return false;
58	  try {
59	    return window.localStorage.getItem(key) === "1";
60	  } catch {
61	    return false;
62	  }
63	}
64	
65	function markIntroSeen(userId: string): void {
66	  const key = introSeenKey(userId);
67	  if (!key) return;
68	  try {
69	    window.localStorage.setItem(key, "1");
70	  } catch {
71	    // localStorage unavailable (private mode, etc.) — silently skip.
72	  }
73	}
74	
75	function clearIntroSeen(userId: string): void {
76	  const key = introSeenKey(userId);
77	  if (!key) return;
78	  try {
79	    window.localStorage.removeItem(key);
80	  } catch {}
81	}
82	
83	export default function Onboarding() {
84	  const { state, stage, dispatch, restart } = useOnboarding({
85	    skipAutoRedirect: true,
86	  });
87	  const userId = useUserStore((s) => s.userId);
88	  // Zustand `persist` hydrates from localStorage asynchronously, so on first
89	  // render `userId` is "" and the seen-marker (keyed by userId) cannot be
90	  // resolved. Start with `null` (unknown) and resolve once the userId lands
91	  // — otherwise the intro replays on every reload and after OAuth redirects.
92	  const [introDone, setIntroDone] = useState<boolean | null>(() =>
93	    userId ? hasSeenIntro(userId) : null,
94	  );
95	
96	  useEffect(() => {
97	    if (!userId) return;
98	    setIntroDone((prev) => (prev === null ? hasSeenIntro(userId) : prev));
99	  }, [userId]);
100	
101	  const handleRestart = () => {
102	    clearIntroSeen(userId);
103	    setIntroDone(false);
104	    return restart();
105	  };
106	
107	  const handleIntroComplete = () => {
108	    markIntroSeen(userId);
109	    setIntroDone(true);
110	  };
111	
112	  const { welcome: welcomeChat, todoDemo: todoDemoChat } = useChatStage(
113	    state,
114	    dispatch,
115	  );
116	
117	  const stageContent = (() => {
118	    switch (stage) {
119	      case "questions":
120	      case "focus":
121	      case "clarify":
122	      case "processing":
123	        return null;
124	      case "revealWriting":
125	        return <RevealWritingStyle state={state} />;
126	      case "revealTodos":
127	        return (
128	          <RevealTodos state={state} dispatch={dispatch} chat={todoDemoChat} />
129	        );
130	      case "workflows":
131	        return <Workflows state={state} dispatch={dispatch} />;
132	      case "platforms":
133	        return <Platforms state={state} dispatch={dispatch} />;
134	      case "chat":
135	        return <Chat state={state} />;
136	    }
137	  })();
138	
139	  const composer = (() => {
140	    switch (stage) {
141	      case "questions":
142	        return <QuestionsComposer state={state} dispatch={dispatch} />;
143	      case "focus":
144	        return <FocusComposer state={state} dispatch={dispatch} />;
145	      case "clarify":
146	        return <ClarifyComposer state={state} dispatch={dispatch} />;
147	      case "processing":
148	        return null;
149	      case "revealWriting":
150	        return <RevealWritingStyleComposer state={state} dispatch={dispatch} />;
151	      case "revealTodos":
152	        return <RevealTodosComposer dispatch={dispatch} chat={todoDemoChat} />;
153	      case "workflows":
154	        return <WorkflowsComposer state={state} dispatch={dispatch} />;
155	      case "platforms":
156	        return <PlatformsComposer state={state} dispatch={dispatch} />;
157	      case "chat":
158	        return <ChatComposer state={state} />;
159	    }
160	  })();
161	
162	  const wrappedComposer = introDone ? (
163	    <m.div {...INTRO_FADE_IN}>{composer}</m.div>
164	  ) : null;
165	
166	  // While `introDone` is null we don't yet know whether to play the intro
167	  // (userId hasn't hydrated). Render nothing rather than briefly mounting
168	  // the intro and then unmounting it once we discover it's already seen.
169	  const introResolved = introDone !== null;
170	
171	  return (
172	    <>
173	      <OnboardingShell
174	        state={state}
175	        stage={stage}
176	        onRestart={handleRestart}
177	        composer={wrappedComposer}
178	      >
179	        {introDone ? (
180	          <m.div {...INTRO_FADE_IN}>
181	            <MessagesRegion state={state} stage={stage} />
182	            <CompletedStagesTimeline
183	              state={state}
184	              dispatch={dispatch}
185	              chat={todoDemoChat}
186	            />
187	            {stageContent}
188	          </m.div>
189	        ) : null}
190	      </OnboardingShell>
191	      <AnimatePresence>
192	        {introResolved && !introDone && (
193	          <OnboardingIntro onComplete={handleIntroComplete} />
194	        )}
195	      </AnimatePresence>
196	    </>
197	  );
198	}
