.navbar {
  -webkit-backdrop-filter: blur(16px) saturate(180%);
  align-items: center;
  backdrop-filter: blur(16px) saturate(180%);
  background: rgba(32, 32, 32, 0.234);
  border-radius: 8px;
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.2);
  display: flex;
  justify-content: center;
  padding: 0.5rem 1rem;
  position: fixed;
  top: 1rem;
  transition: border-radius ease 0.1s;
  z-index: 1;
}

.navbar:hover {
  background-color: #18181b;
  border-radius: 8px 8px 0 0;
}

.pdf_container {
  border-radius: 10px;
  max-height: 150px;
  max-width: 330px;
  min-height: 150px;
  min-width: 330px;
  overflow: hidden;
}

.searchbar {
  width: 50%;
}

.searchbar input:disabled {
  cursor: wait;
}

.searchbar_container {
  align-items: center;
  display: flex;
  flex-direction: column;
  justify-content: center;
  padding-top: 0.8rem;
  width: 100%;
}

.sidebar div::-webkit-scrollbar {
  opacity: 0;
}

.sidebar div::-webkit-scrollbar {
  border-radius: 100px;
  width: 4px;
}

.sidebar div::-webkit-scrollbar-thumb {
  background: transparent;
  border-radius: 100px;
}

.sidebar:hover div::-webkit-scrollbar-thumb {
  background: #5e5e5e;
}

.tiptap {
  outline: none;
}

.tiptap:focus-visible {
  outline: 2px solid var(--color-primary);
  outline-offset: 2px;
}

/* OpenUI document card — outline only; let the conversation scroll the body */
.openui-document .tiptap {
  outline: none;
}

/* Restore the keyboard focus ring inside OpenUI document cards so keyboard
   users keep a visible focus indicator. */
.openui-document .tiptap:focus-visible {
  outline: 2px solid var(--color-primary);
  outline-offset: 2px;
}

/* Mail reply editor — overflow only; height is capped by the parent max-h-[250px] wrapper */
.mail-editor .tiptap {
  overflow: auto;
}

.user_container_inner {
  align-items: center;
  display: flex;
  flex-direction: row;
  height: fit-content;
  justify-content: space-between;
  min-height: 50px;
  overflow: hidden;
  width: 100%;
}

.animate-scale-in {
  animation: scale-in 0.4s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
}

.animate-scale-in-blur {
  animation: scale-in-blur 0.5s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
}

