function autoClose(input) {
    const stack = [];
    let inStr = false, esc = false;
    for (let i = 0; i < input.length; i++) {
        const c = input[i];
        if (esc) {
            esc = false;
            continue;
        }
        if (c === "\\" && inStr) {
            esc = true;
            continue;
        }
        if (c === '"') {
            inStr = !inStr;
            continue;
        }
        if (inStr)
            continue;
        if (c === "(" || c === "[" || c === "{")
            stack.push(c);
        else if (c === ")" && stack[stack.length - 1] === "(")
            stack.pop();
        else if (c === "]" && stack[stack.length - 1] === "[")
            stack.pop();
        else if (c === "}" && stack[stack.length - 1] === "{")
            stack.pop();
    }
    const wasIncomplete = inStr || stack.length > 0;
    if (!wasIncomplete)
        return { text: input, wasIncomplete: false };
    let out = input;
    if (inStr) {
        if (esc)
            out += "\\";
        out += '"';
    } // close open string
    for (let j = stack.length - 1; j >= 0; j-- // close brackets in reverse
    )
        out += stack[j] === "(" ? ")" : stack[j] === "[" ? "]" : "}";
    return { text: out, wasIncomplete: true };
}
// lexer
function tokenize(src) {
    const tokens = [];
    let i = 0;
    const n = src.length;
    while (i < n) {
        // Skip horizontal whitespace (not newlines — they're significant)
        while (i < n && (src[i] === " " || src[i] === "\t" || src[i] === "\r"))
            i++;
        if (i >= n)
            break;
        const c = src[i];
        // ── Single-character punctuation ──────────────────────────────────────
        if (c === "\n") {
            tokens.push({ t: 0 /* T.Newline */ });
            i++;
            continue;
        }
        if (c === "(") {
            tokens.push({ t: 1 /* T.LParen */ });
            i++;
            continue;
        }
        if (c === ")") {
            tokens.push({ t: 2 /* T.RParen */ });
            i++;
            continue;
        }
        if (c === "[") {
            tokens.push({ t: 3 /* T.LBrack */ });
            i++;
